// Helper to write database
function writeDb(data: any) {
  try {
    fs.writeFileSync(DATA_FILE, JSON.stringify(data, null, 2));
  } catch (err) {
    console.error("Error writing DB file:", err);
  }
}

// Helper to trigger external sheets webhook if configured
async function triggerSheetsWebhook(record: any, action: string, settings: any) {
  if (!settings.sheetsWebhookUrl) return;
  try {
    const payload = {
      action: action,
      record: {
        TEAM: record.team,
        PROYECTO: record.proyecto,
        DPTO: record.dpto,
        ESTAC: record.estac,
        DEP: record.dep,
        ASESOR: record.asesor,
        TIPO: record.tipo,
        SOLICITUD: record.solicitud,
        EMISION: record.emision,
        STATUS: record.status,
        COMENTARIO: record.comentario,
        id: record.id
      }
    };
    
    await fetch(settings.sheetsWebhookUrl, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(payload)
    }).catch(e => console.error("Webhook fetch failed:", e));
  } catch (e) {
    console.error("Error triggering sheets webhook:", e);
  }
}

// Helper to format date-time exactly like Peru's timezone (PET)
function getFormattedSystemDateTime(): string {
  const now = new Date();
  const day = String(now.getDate()).padStart(2, "0");
  const month = String(now.getMonth() + 1).padStart(2, "0");
  const year = now.getFullYear();
  const hours = String(now.getHours()).padStart(2, "0");
  const minutes = String(now.getMinutes()).padStart(2, "0");
  const seconds = String(now.getSeconds()).padStart(2, "0");
  return `${day}/${month}/${year} ${hours}:${minutes}:${seconds}`;
}

// API Routes
app.get("/api/records", (req, res) => {
  const db = readDb();
  res.json(db.records);
});

app.post("/api/records", async (req, res) => {
  const db = readDb();
  
  // Auto-resolve team based on project if not provided
  let team = req.body.team || "";
  const proyectoName = req.body.proyecto || "";
  if (proyectoName && db.settings.proyectos) {
    const matched = db.settings.proyectos.find((p: any) => p.name.toLowerCase() === proyectoName.toLowerCase());
    if (matched) {
      team = matched.team;
    }
  }

  // Automatic assistant assignment logic based on project ownership
  let derivadoA = req.body.derivadoA;
  if (!derivadoA && proyectoName && db.settings.users) {
    const assistants = db.settings.users.filter((u: any) => 
      u.role === "Asistente Legal" && 
      u.active && 
      u.assignedProjects && 
      u.assignedProjects.some((p: string) => p.toLowerCase() === proyectoName.toLowerCase())
    );
    if (assistants.length > 0) {
      derivadoA = assistants[0].username;
    }
  }

  // Auto-stamp solicitud for Jefe Legal / Admin operations if they provide a tipo
  let solicitud = req.body.solicitud;
  let solicitudAt = req.body.solicitudAt;
  if (!solicitud && req.body.tipo) {
    solicitud = getFormattedSystemDateTime();
    solicitudAt = new Date().toISOString();
  }

  const newRecord = {
    id: `rec-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
    team: team,
    proyecto: proyectoName,
    dpto: req.body.dpto || "",
    estac: req.body.estac || "",
    dep: req.body.dep || "",
    asesor: req.body.asesor || "",
    tipo: req.body.tipo || "",
    solicitud: solicitud || "",
    solicitudAt: solicitudAt || (solicitud ? new Date().toISOString() : undefined),
    emision: req.body.emision || "",
    emittedAt: req.body.emittedAt || (req.body.emision ? new Date().toISOString() : undefined),
    status: req.body.status || "",
    comentario: req.body.comentario || "",
    derivadoA: derivadoA,
    history: req.body.status ? [{
      status: req.body.status,
      comentario: req.body.comentario || "Registro inicial.",
      timestamp: getFormattedSystemDateTime(),
      user: req.body.updatedByUser || "Sistema"
    }] : [],
    createdAt: new Date().toISOString()
  };
  
  db.records.unshift(newRecord);
  writeDb(db);
  
  await triggerSheetsWebhook(newRecord, "INSERT", db.settings);
  
  res.status(201).json(newRecord);
});

// Update record
app.put("/api/records/:id", async (req, res) => {
  const db = readDb();
  const index = db.records.findIndex((r: any) => r.id === req.params.id);
  if (index === -1) {
    return res.status(404).json({ error: "Record not found" });
  }
  
  // Auto-resolve team if project was changed
  let team = req.body.team || db.records[index].team;
  const proyectoName = req.body.proyecto || db.records[index].proyecto;
  if (proyectoName && db.settings.proyectos) {
    const matched = db.settings.proyectos.find((p: any) => p.name.toLowerCase() === proyectoName.toLowerCase());
    if (matched) {
      team = matched.team;
    }
  }

  // Automatic assistant assignment if changed or if it was empty and project changed
  let derivadoA = req.body.derivadoA !== undefined ? req.body.derivadoA : db.records[index].derivadoA;
  if (!derivadoA && proyectoName && db.settings.users) {
    const assistants = db.settings.users.filter((u: any) => 
      u.role === "Asistente Legal" && 
      u.active && 
      u.assignedProjects && 
      u.assignedProjects.some((p: string) => p.toLowerCase() === proyectoName.toLowerCase())
    );
    if (assistants.length > 0) {
      derivadoA = assistants[0].username;
    }
  }

  // Auto-stamp dates
  let solicitud = req.body.solicitud || db.records[index].solicitud;
  let solicitudAt = req.body.solicitudAt || db.records[index].solicitudAt;
  
  // If tipo was set for the first time, auto-stamp solicitud!
  if (req.body.tipo && !db.records[index].tipo && !solicitud) {
    solicitud = getFormattedSystemDateTime();
    solicitudAt = new Date().toISOString();
  }

  let emision = req.body.emision || db.records[index].emision;
  let emittedAt = req.body.emittedAt || db.records[index].emittedAt;

  // Auto-stamp emision if status or comment changes
  const statusChanged = req.body.status !== undefined && req.body.status !== db.records[index].status;
  const commentChanged = req.body.comentario !== undefined && req.body.comentario !== db.records[index].comentario;

  if (statusChanged || commentChanged) {
    emision = getFormattedSystemDateTime();
    emittedAt = new Date().toISOString();
  }

  // Manage History
  let history = db.records[index].history || [];
  if (statusChanged || commentChanged) {
    const historyEntry = {
      status: req.body.status !== undefined ? req.body.status : (db.records[index].status || "Pendiente"),
      comentario: req.body.comentario !== undefined ? req.body.comentario : (db.records[index].comentario || ""),
      timestamp: getFormattedSystemDateTime(),
      user: req.body.updatedByUser || "Usuario"
    };
    history = [...history, historyEntry];
  }

  const updated = {
    ...db.records[index],
    ...req.body,
    team: team,
    derivadoA: derivadoA,
    solicitud: solicitud,
    solicitudAt: solicitudAt,
    emision: emision,
    emittedAt: emittedAt,
    history: history,
    id: db.records[index].id // Ensure ID doesn't change
  };
  
  db.records[index] = updated;
  writeDb(db);
  
  await triggerSheetsWebhook(updated, "UPDATE", db.settings);
  
  res.json(updated);
});

// Delete record
app.delete("/api/records/:id", async (req, res) => {
  const db = readDb();
  const index = db.records.findIndex((r: any) => r.id === req.params.id);
  if (index === -1) {
    return res.status(404).json({ error: "Record not found" });
  }
  
  const deleted = db.records.splice(index, 1)[0];
  writeDb(db);
  
  await triggerSheetsWebhook(deleted, "DELETE", db.settings);
  
  res.json({ success: true, deletedId: req.params.id });
});

